import{_ as i,o as s,c as a,a2 as l}from"./chunks/framework.CGYl2SZ_.js";const t=JSON.parse('{"title":"markdown formatting","description":"markdown formatting 页面","frontmatter":{"title":"markdown formatting","description":"markdown formatting 页面"},"headers":[],"relativePath":"concepts/markdown-formatting.md","filePath":"concepts/markdown-formatting.md"}');const n=i({name:"concepts/markdown-formatting.md"},[["render",function(i,t,n,e,h,o){return s(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="markdown-格式化" tabindex="-1">Markdown 格式化 <a class="header-anchor" href="#markdown-格式化" aria-label="Permalink to &quot;Markdown 格式化&quot;">​</a></h1><h1 id="markdown-格式化-1" tabindex="-1">Markdown 格式化 <a class="header-anchor" href="#markdown-格式化-1" aria-label="Permalink to &quot;Markdown 格式化&quot;">​</a></h1><p>OpenClaw 通过在渲染渠道特定输出之前将出站 Markdown 转换为共享中间表示（IR）来格式化。IR 保持源文本完整，同时携带样式/链接跨度，以便分块和渲染可以在渠道间保持一致。</p><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><ul><li><strong>一致性</strong>：一次解析，多个渲染器。</li><li><strong>安全分块</strong>：在渲染之前拆分文本，以便内联格式永远不会跨块断开。</li><li><strong>渠道适配</strong>：将相同的 IR 映射到 Slack mrkdwn、Telegram HTML 和 Signal 样式范围，而无需重新解析 Markdown。</li></ul><h2 id="管道" tabindex="-1">管道 <a class="header-anchor" href="#管道" aria-label="Permalink to &quot;管道&quot;">​</a></h2><ol><li><strong>解析 Markdown → IR</strong><ul><li>IR 是纯文本加样式跨度（粗体/斜体/删除线/代码/剧透）和链接跨度。</li><li>偏移量是 UTF-16 代码单元，以便 Signal 样式范围与其 API 对齐。</li><li>仅在渠道选择加入表格转换时解析表格。</li></ul></li><li><strong>分块 IR（格式优先）</strong><ul><li>分块在渲染之前的 IR 文本上发生。</li><li>内联格式不会跨块拆分；范围按块切片。</li></ul></li><li><strong>按渠道渲染</strong><ul><li><strong>Slack</strong>：mrkdwn 标记（粗体/斜体/删除线/代码），链接为 <code>&lt;url|label&gt;</code>。</li><li><strong>Telegram</strong>：HTML 标签（<code>&lt;b&gt;</code>、<code>&lt;i&gt;</code>、<code>&lt;s&gt;</code>、<code>&lt;code&gt;</code>、<code>&lt;pre&gt;&lt;code&gt;</code>、<code>&lt;a href&gt;</code>）。</li><li><strong>Signal</strong>：纯文本 + <code>text-style</code> 范围；链接在标签与 URL 不同时变为 <code>label (url)</code>。</li></ul></li></ol><h2 id="ir-示例" tabindex="-1">IR 示例 <a class="header-anchor" href="#ir-示例" aria-label="Permalink to &quot;IR 示例&quot;">​</a></h2><p>输入 Markdown：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Hello </span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**world**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — see [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">docs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">https://docs.openclaw.ai</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span></span></code></pre></div><p>IR（示意图）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;text&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello world — see docs.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;styles&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;start&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;end&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;style&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }],</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;links&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;start&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">19</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;end&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">23</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;href&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://docs.openclaw.ai&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="使用位置" tabindex="-1">使用位置 <a class="header-anchor" href="#使用位置" aria-label="Permalink to &quot;使用位置&quot;">​</a></h2><ul><li>Slack、Telegram 和 Signal 出站适配器从 IR 渲染。</li><li>其他渠道（WhatsApp、iMessage、MS Teams、Discord）仍使用纯文本或自己的格式化规则，在启用时在分块前应用 Markdown 表格转换。</li></ul><h2 id="表格处理" tabindex="-1">表格处理 <a class="header-anchor" href="#表格处理" aria-label="Permalink to &quot;表格处理&quot;">​</a></h2><p>Markdown 表格在聊天客户端中支持不一致。使用 <code>markdown.tables</code> 控制每个渠道（和每个账户）的转换。</p><ul><li><code>code</code>：将表格渲染为代码块（大多数渠道的默认设置）。</li><li><code>bullets</code>：将每行转换为项目符号点（Signal + WhatsApp 的默认设置）。</li><li><code>off</code>：禁用表格解析和转换；原始表格文本通过。</li></ul><p>配置键：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    markdown</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      tables</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">code</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  accounts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    work</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      markdown</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        tables</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">off</span></span></code></pre></div><h2 id="分块规则" tabindex="-1">分块规则 <a class="header-anchor" href="#分块规则" aria-label="Permalink to &quot;分块规则&quot;">​</a></h2><ul><li>分块限制来自渠道适配器/配置，并应用于 IR 文本。</li><li>代码围栏作为单个块保留，带尾随换行符，以便渠道正确渲染它们。</li><li>列表前缀和块引用前缀是 IR 文本的一部分，因此分块不会在中间前缀拆分。</li><li>内联样式（粗体/斜体/删除线/内联代码/剧透）永远不会跨块拆分；渲染器在每个块内重新打开样式。</li></ul><p>如果您需要更多关于跨渠道分块行为的信息，请参阅<a href="/concepts/streaming.html">流式传输 + 分块</a>。</p><h2 id="链接策略" tabindex="-1">链接策略 <a class="header-anchor" href="#链接策略" aria-label="Permalink to &quot;链接策略&quot;">​</a></h2><ul><li><strong>Slack</strong>：<code>[label](url)</code> -&gt; <code>&lt;url|label&gt;</code>；裸 URL 保持裸。自动链接在解析时禁用以避免重复链接。</li><li><strong>Telegram</strong>：<code>[label](url)</code> -&gt; <code>&lt;a href=&quot;url&quot;&gt;label&lt;/a&gt;</code>（HTML 解析模式）。</li><li><strong>Signal</strong>：<code>[label](url)</code> -&gt; <code>label (url)</code>，除非标签与 URL 匹配。</li></ul><h2 id="剧透" tabindex="-1">剧透 <a class="header-anchor" href="#剧透" aria-label="Permalink to &quot;剧透&quot;">​</a></h2><p>剧透标记（<code>||spoiler||</code>）仅针对 Signal 解析，它们映射到 SPOILER 样式范围。其他渠道将它们视为纯文本。</p><h2 id="如何添加或更新渠道格式化器" tabindex="-1">如何添加或更新渠道格式化器 <a class="header-anchor" href="#如何添加或更新渠道格式化器" aria-label="Permalink to &quot;如何添加或更新渠道格式化器&quot;">​</a></h2><ol><li><strong>一次解析</strong>：使用共享的 <code>markdownToIR(...)</code> 辅助函数和渠道适当的选项（自动链接、标题样式、块引用前缀）。</li><li><strong>渲染</strong>：使用 <code>renderMarkdownWithMarkers(...)</code> 和样式标记映射（或 Signal 样式范围）实现渲染器。</li><li><strong>分块</strong>：在渲染前调用 <code>chunkMarkdownIR(...)</code>；渲染每个块。</li><li><strong>接线适配器</strong>：更新渠道出站适配器以使用新的分块器和渲染器。</li><li><strong>测试</strong>：添加或更新格式测试，如果渠道使用分块，则添加出站传递测试。</li></ol><h2 id="常见陷阱" tabindex="-1">常见陷阱 <a class="header-anchor" href="#常见陷阱" aria-label="Permalink to &quot;常见陷阱&quot;">​</a></h2><ul><li>Slack 尖括号标记（<code>&lt;@U123&gt;</code>、<code>&lt;#C123&gt;</code>、<code>&lt;https://...&gt;</code>）必须保留；安全地转义原始 HTML。</li><li>Telegram HTML 需要在标签外转义文本以避免破坏的标记。</li><li>Signal 样式范围依赖于 UTF-16 偏移；不要使用代码点偏移。</li><li>保留围栏代码块的尾随换行符，以便关闭标记位于自己的行上。</li></ul>',30)])])}]]);export{t as __pageData,n as default};
